function canvasPngBlob(canvas){return new Promise((resolve,reject)=>{try{canvas.toBlob(blob=>blob?resolve(blob):reject(new Error('O navegador não conseguiu converter a captura em PNG.')),'image/png',1);}catch(err){reject(err);}});}
