async function compatibleViewPngBlob(view){const title=text(view.querySelector('h1')?.textContent)||'CRM Comercial',subtitle=text(view.querySelector('.page-heading p:not(.eyebrow)')?.textContent),raw=Array.from(view.querySelectorAll('h2,h3,strong,small,p,td,th')).map(el=>text(el.textContent)).filter(Boolean),lines=[];raw.forEach(line=>{const clean=line.replace(/\s+/g,' ');for(let i=0;i<clean.length;i+=92)lines.push(clean.slice(i,i+92));});const width=1400,height=Math.min(5000,Math.max(760,190+Math.min(lines.length,165)*25)),canvas=document.createElement('canvas');canvas.width=width;canvas.height=height;const ctx=canvas.getContext('2d',{alpha:false});if(!ctx)throw new Error('Canvas indisponível neste navegador.');ctx.fillStyle='#f4f7fb';ctx.fillRect(0,0,width,height);ctx.fillStyle='#073B5C';ctx.font='700 34px Arial';ctx.fillText(title,54,70);ctx.fillStyle='#647B8C';ctx.font='18px Arial';ctx.fillText(subtitle,54,104);ctx.strokeStyle='#DCE6EF';ctx.beginPath();ctx.moveTo(54,132);ctx.lineTo(width-54,132);ctx.stroke();ctx.fillStyle='#17354B';ctx.font='16px Arial';lines.slice(0,165).forEach((line,i)=>ctx.fillText(line,54,174+i*25));ctx.fillStyle='#647B8C';ctx.font='13px Arial';ctx.fillText('Captura gerada em modo compatível pelo CRM Comercial.',54,height-28);return canvasPngBlob(canvas);}
function downloadPng(blob){const url=URL.createObjectURL(blob),a=document.createElement('a');a.href=url;a.download=`crm-${state.view}-${today()}.png`;a.style.display='none';document.body.appendChild(a);a.click();a.remove();setTimeout(()=>URL.revokeObjectURL(url),2500);}
async function saveCurrentViewAsImage(e){const btn=e&&e.currentTarget;try{if(btn)btn.disabled=true;const view=$('.view:not(.hidden)');if(!view)return;let blob,fallbackUsed=false;try{blob=await richViewPngBlob(view);}catch(err){fallbackUsed=true;console.warn('[CRM] Captura visual completa indisponível. Usando modo compatível.',err);blob=await compatibleViewPngBlob(view);}downloadPng(blob);toast(fallbackUsed?'Imagem PNG salva em modo compatível.':'Imagem PNG salva.');}catch(err){toast('Não foi possível salvar a imagem PNG.',true);console.error(err);}finally{if(btn)btn.disabled=false;}}

